{
  "type": "DRAG_FILL",
  "lessonText": "Engage in a fun challenge to learn about healthy relationships.",
  "data": {
    "challenges": [
      {
        "instruction": "Fill in the blanks with the correct terms related to consent.",
        "codeTemplate": "Consent is ___, ongoing, and can be ___ at any time.",
        "options": ["enthusiastic", "withdrawn", "mandatory", "optional"],
        "correctAnswer": "enthusiastic, withdrawn",
        "explanation": "Consent must be enthusiastic and can be withdrawn at any time."
      },
      {
        "instruction": "Complete the statement about boundaries.",
        "codeTemplate": "Respecting someone's ___ is crucial in any relationship.",
        "options": ["privacy", "time", "money", "space"],
        "correctAnswer": "privacy",
        "explanation": "Respecting privacy is essential for healthy interactions."
      },
      {
        "instruction": "Identify the key elements of a healthy relationship.",
        "codeTemplate": "A healthy relationship includes ___, communication, and ___ support.",
        "options": ["trust", "criticism", "distance", "financial"],
        "correctAnswer": "trust, support",
        "explanation": "Trust and support are fundamental components of a healthy relationship."
      }
    ]
  }
}
